  ('2026-02-17', 'general', 'general', 'Year of the Fire Horse begins today. Across the board, energy runs hot and home-centered, family before ambition. House of Family rules, so anything tethered to where you live, who you live with, and who you''d call from a hard day gets a tailwind. Most signs ride 60/40 in their favor. Dragons and Sheep, ease off the gas.', 62, 'favorable', '{"date": "2026-02-17", "user_sign": null, "category": "general", "pillars": {"year": {"element": "Fire", "sign": "Horse"}, "month": {"element": "Metal", "sign": "Tiger"}, "day": {"element": "Water", "sign": "Dog"}}, "scores": {"primary": 62, "sexagenary_60x12": null, "matrix_12x12": null, "matrix_flag": ""}, "tone": "favorable", "amplified_domains": ["Leisure", "Mental", "Social/Style", "Travel"], "focus_domains": ["Action", "Mental", "Home/Family", "Health", "Travel", "Leisure"], "amplified_in_focus": ["Mental", "Travel", "Leisure"], "matrix_keywords": {}, "all_domain_keywords": {}, "house": "House of Family - anything that has to do with loyalty, support and protection and providing for one''s family are favored", "voice": {}, "match_day": null, "user_sign_relations": null, "western_moment": null}'::jsonb);
